const COURSES = [
  {
    id:'start', icon:'💼', title:'Как начать инвестировать', subtitle:'Понятный старт: цели, инструменты, биржа, брокер, сделки и риски.', level:'Старт', track:'start', accent:'#15b985', visual:'cash',
    lessons:[
      lesson('start-1','Зачем инвестировать','7 минут','После урока вы поймете, почему сбережения теряют покупательную способность и как инвестиции могут помочь сохранить капитал.', ['инфляция','цель','капитал'], 'inflation',
        ['Деньги, которые просто лежат на карте или наличными, кажутся безопасными. Но у них есть тихий противник — инфляция. Если цены растут, на ту же сумму со временем можно купить меньше товаров и услуг.', 'Инвестиции не гарантируют доход, но дают шанс сохранить или увеличить покупательную способность капитала. Важно не начинать с “что купить”, а сначала понять, зачем вам деньги, когда они понадобятся и какую просадку вы готовы выдержать.'],
        {title:'Пример', text:'Если у вас есть 300 000 ₽ на цель через пять лет, хранить всю сумму без доходности рискованно: инфляция постепенно уменьшит её реальную ценность. Тренажёр ниже покажет, как меняется покупательная способность денег.'},
        'Сначала сформулируйте цель: сумма, срок и регулярный взнос. Так проще выбрать между вкладом, облигациями, фондами, акциями и ИИС-3.', ['Определить сумму цели','Записать срок, когда деньги понадобятся','Оставить резерв отдельно от инвестиционных денег'],
        [q('Что делает инфляция со сбережениями?', ['Увеличивает количество денег на счёте','Постепенно снижает покупательную способность','Гарантирует доход выше вклада'],1,'Инфляция не уменьшает номинальную сумму, но снижает то, что на неё можно купить.'), q('С чего разумнее начать инвестиции?', ['С выбора самой популярной акции','С цели, срока и резерва','С ежедневных сделок'],1,'План помогает выбрать инструменты и не принимать решения на эмоциях.'), q('Инвестиции гарантируют доход?', ['Нет, результат зависит от выбранных активов и рыночной ситуации','Да, если инвестировать надолго','Да, если купить известные компании'],0,'Даже долгосрочные инвестиции связаны с риском, но грамотный подход помогает управлять им.')] ),
      lesson('start-2','Какие бывают инструменты','8 минут','После урока вы поймете, чем отличаются вклад, облигации, акции, фонды и золото.', ['вклад','облигации','акции','фонды'], 'goal',
        ['Инструменты отличаются не только доходностью. Важно смотреть на риск, срок, ликвидность и понятность. Вклад проще, облигация ближе к займу, акция — доля в бизнесе, фонд — готовая корзина активов.', 'Начинающему инвестору не нужно сразу знать всё. Достаточно понять роль каждого инструмента: что может дать стабильность, что отвечает за рост, а что помогает распределить риск.'],
        {title:'Как это выглядит в АКБФ', text:'В приложении АКБФ Трейд инструменты можно смотреть по карточкам: цена, динамика, описание, параметры и кнопка действия. Начинайте с инструментов, принцип работы которых вы понимаете.'},
        'Не сравнивайте инструменты только по доходности. Высокая потенциальная доходность почти всегда означает более высокий риск.', ['Разделить инструменты на понятные и непонятные','Отметить, какие подходят вашему сроку','Не вкладывать деньги в инструмент без понимания риска'],
        [q('Что такое акция?', ['Доля в бизнесе компании','Банковский вклад','Долговая расписка государства'],0,'Акция даёт участие в бизнесе, но не гарантирует доход.'), q('Что помогает купить сразу набор активов?', ['Один пай фонда','Только срочный вклад','Кредитная карта'],0,'Фонд собирает внутри разные активы и продаёт инвестору пай.'), q('Почему нельзя выбирать инструмент только по доходности?', ['Потому что важны риск, срок и ликвидность','Потому что доходность всегда одинаковая','Потому что брокер сам выбирает активы'],0,'Доходность без оценки риска может привести к неподходящему решению.')] ),
      lesson('start-3','Биржа, брокер и сделка','8 минут','После урока вы поймете, зачем нужен брокер и как проходит покупка ценной бумаги.', ['биржа','брокер','депозитарий'], 'trade',
        ['Биржа — это организованная площадка, где встречаются заявки покупателей и продавцов. Частный инвестор выходит на биржу через брокера: он открывает счёт, передаёт поручения и ведёт учёт операций.', 'После сделки деньги и бумаги не “летают” вручную. Расчёты проходят через инфраструктуру рынка, а права на ценные бумаги учитываются в депозитарии. Поэтому важно выбирать лицензированного брокера.'],
        {title:'В приложении', text:'В АКБФ Трейд пользователь выбирает инструмент, нажимает “Купить” или “Продать”, указывает количество и подтверждает поручение. После исполнения результат появляется в портфеле.'},
        'Брокер не заменяет инвестиционное решение. Он даёт доступ к рынку и исполняет поручения, а выбор инструмента остаётся за инвестором.', ['Проверить наличие брокерского счёта','Понять, где в приложении смотреть портфель','Не подтверждать сделку, пока не понятны цена и количество'],
        [q('Зачем нужен брокер?', ['Чтобы частный инвестор мог совершать сделки на бирже','Чтобы гарантировать доходность','Чтобы отменять рыночный риск'],0,'Брокер даёт доступ к торгам и исполняет поручения инвестора.'), q('Где учитываются права на ценные бумаги?', ['В депозитарии','В кошельке браузера','На банковской карте'],0,'Депозитарий ведёт учёт прав собственности на бумаги.'), q('Кто принимает решение о покупке?', ['Инвестор','Биржа автоматически','Депозитарий'],0,'Брокер исполняет поручение, но решение принимает инвестор.')] ),
      lesson('start-4','Заявки: купить, продать и не переплатить','9 минут','После урока вы поймете разницу между рыночной и лимитной заявкой.', ['лот','рыночная заявка','лимитная заявка'], 'trade',
        ['На бирже сделка начинается с заявки. В рыночной заявке вы соглашаетесь на текущую доступную цену. Это быстро, но при недостаточной ликвидности фактическая цена может отличаться.', 'Лимитная заявка помогает контролировать цену: вы заранее указываете, дороже какой цены не готовы покупать или дешевле какой не готовы продавать. Такая заявка может не исполниться, зато защищает от неприятного сюрприза.'],
        {title:'Мини-сценарий', text:'Если акция стоит около 100 ₽, а вы готовы купить только по 98 ₽, используйте лимитную заявку. Если нужно купить сразу и вы принимаете рыночную цену — подойдёт рыночная заявка.'},
        'Перед подтверждением заявки проверьте инструмент, количество, тип заявки, цену и комиссию.', ['Понять, какой тип заявки подходит ситуации','Проверить количество лотов','Не нажимать “Подтвердить”, если цена непонятна'],
        [q('Что делает лимитная заявка?', ['Позволяет указать желаемую цену сделки','Гарантирует прибыль','Покупает актив без брокера'],0,'Лимитная заявка исполняется только при подходящей цене.'), q('Когда рыночная заявка может быть неудобна?', ['Когда в стакане мало заявок и цена может отличаться','Когда рынок закрыт навсегда','Когда актив всегда растёт'],0,'При низкой ликвидности возможна покупка или продажа по менее выгодной цене.'), q('Что нужно проверить перед сделкой?', ['Инструмент, количество, цену и комиссию','Только цвет кнопки','Только название брокера'],0,'Ошибки чаще всего возникают из-за невнимательности к деталям заявки.')] ),
      lesson('start-5','Риски и первый портфель','10 минут','После урока вы поймете, как снизить риск с помощью резерва, срока и диверсификации.', ['риск','диверсификация','портфель'], 'portfolio',
        ['Риск — это не только вероятность убытка, но и готовность выдержать временное снижение стоимости портфеля. Даже хорошие инструменты могут дешеветь, если рынок проходит сложный период.', 'Снизить риск помогает диверсификация: не вкладывать всё в одну идею, а распределять капитал между инструментами. Для новичка это особенно важно, потому что один неудачный выбор не должен ломать весь план.'],
        {title:'Пример портфеля', text:'Для спокойного старта часть денег можно оставить в ликвидных инструментах, часть направить в облигации или фонды, а долю акций увеличивать постепенно по мере опыта.'},
        'Первый портфель должен быть понятным. Если вы не можете объяснить, зачем в портфеле актив, лучше отложить покупку.', ['Не инвестировать резерв','Разделить капитал между несколькими инструментами','Проверить, сможете ли выдержать просадку'],
        [q('Что такое диверсификация?', ['Распределение денег между разными активами','Покупка одной акции на всю сумму','Отказ от инвестиций'],0,'Диверсификация снижает зависимость результата от одной идеи.'), q('Какие деньги не стоит инвестировать?', ['Резерв на жизнь и непредвиденные расходы','Деньги на долгосрочную цель','Свободные средства после обязательных расходов'],0,'Резерв должен быть доступен и не зависеть от колебаний рынка.'), q('Почему важен срок инвестирования?', ['Он помогает выбрать подходящий уровень риска','Он гарантирует доходность','Он отменяет налоги'],0,'Чем короче срок, тем осторожнее должны быть инструменты.')] )
    ]
  },
  {
    id:'iis', icon:'🧾', title:'Как пользоваться ИИС-3', subtitle:'Налоговые льготы, сроки, пополнения и сценарии использования.', level:'Старт', track:'start', accent:'#0a7a63', visual:'iis',
    lessons:[
      lesson('iis-1','Что такое ИИС-3','8 минут','После урока вы поймете, чем ИИС-3 отличается от обычного брокерского счёта.', ['ИИС-3','налоговые льготы','срок'], 'iis',
        ['ИИС-3 — это инвестиционный счёт с налоговыми льготами. Он подходит тем, кто готов инвестировать на несколько лет и хочет использовать поддержку государства.', 'Главное отличие от обычного брокерского счёта — льготы. Можно вернуть часть НДФЛ с пополнений и освободить доход от налога при соблюдении условий. Но за льготы инвестор берёт на себя ограничение по сроку владения счётом.'],
        {title:'В АКБФ', text:'ИИС-3 можно рассматривать как отдельный счёт для долгосрочной цели. Важно заранее понимать срок, сумму пополнений и инструменты, которые вы планируете покупать.'},
        'ИИС-3 — не замена резерву. Это счёт для денег, которые не понадобятся в ближайшее время.', ['Оценить горизонт инвестирования','Понять, есть ли официальный НДФЛ','Не планировать быстрый вывод денег с ИИС-3'],
        [q('Что отличает ИИС-3 от обычного брокерского счёта?', ['Наличие налоговых льгот при соблюдении условий','Гарантия доходности','Возможность покупать только вклады'],0,'ИИС-3 даёт льготы, но требует соблюдать правила счёта.'), q('Кому особенно полезен вычет на взнос?', ['Тем, кто платит НДФЛ','Тем, кто не имеет доходов','Только пенсионерам'],0,'Вычет на взнос связан с уже уплаченным НДФЛ.'), q('Почему ИИС-3 лучше планировать заранее?', ['Из-за минимального срока владения и условий льгот','Потому что счёт нельзя пополнять','Потому что доход гарантирован'],0,'При раннем закрытии льготы можно потерять.')] ),
      lesson('iis-2','Два налоговых преимущества','9 минут','После урока вы поймете, как работают вычет на взнос и льгота на доход.', ['вычет на взнос','льгота на доход','НДФЛ'], 'iis',
        ['Первое преимущество — вычет на взнос. Пополняя ИИС-3, можно вернуть НДФЛ с суммы до 400 000 ₽ в год. Размер возврата зависит от вашей ставки НДФЛ и суммы налога, которую вы уже заплатили.', 'Второе преимущество — освобождение от налога на инвестиционный доход при закрытии счёта после минимального срока. Это особенно важно для долгосрочного инвестора: часть результата можно сохранить внутри капитала.'],
        {title:'Пример', text:'Если инвестор пополнил ИИС-3 на 400 000 ₽ и платит НДФЛ по ставке 13%, потенциальный вычет составит до 52 000 ₽. При ставке 22% — до 88 000 ₽, если достаточно уплаченного налога.'},
        'Вычет на взнос не появляется автоматически: для него нужен уплаченный НДФЛ. А льгота на доход работает только при соблюдении срока.', ['Проверить свою ставку НДФЛ','Посчитать возможный вычет','Разделить пополнения и инвестиционный результат'],
        [q('С какой суммы считается вычет на взнос?', ['С пополнений до 400 000 ₽ в год','С любой суммы без ограничений','Только с дохода по акциям'],0,'Пополнять можно больше, но вычетная база ограничена 400 000 ₽ в год.'), q('От чего зависит сумма возврата?', ['От ставки НДФЛ и уплаченного налога','От цвета интерфейса приложения','От количества открытых брокеров'],0,'Вернуть можно только налог, который был уплачен.'), q('Когда действует льгота на доход?', ['При закрытии ИИС после соблюдения минимального срока','На следующий день после открытия','Только при покупке акций'],0,'Льгота на доход связана с условиями владения ИИС-3.')] ),
      lesson('iis-3','Срок, пополнения и досрочное закрытие','9 минут','После урока вы поймете, почему срок открытия ИИС-3 важнее даты первого пополнения.', ['срок владения','пополнение','досрочное закрытие'], 'iis',
        ['Срок ИИС-3 считается с даты открытия счёта, а не с даты первого пополнения. Поэтому открыть счёт заранее может быть полезно: минимальный срок начнёт идти, даже если вы пополните его позже.', 'Если закрыть ИИС-3 раньше минимального срока, право на льготы теряется. Уже полученные вычеты придётся вернуть, а инвестиционный доход может облагаться налогом. Поэтому деньги на ИИС-3 лучше не смешивать с резервом.'],
        {title:'Жизненная ситуация', text:'Если вы планируете цель через 5–7 лет, ИИС-3 может быть удобен. Если деньги могут понадобиться через несколько месяцев, лучше выбрать обычный брокерский счёт или более ликвидный инструмент.'},
        'Сначала срок и цель, потом пополнение. Так меньше риск закрыть счёт раньше времени.', ['Записать дату открытия счёта','Понять минимальный срок для своего года открытия','Не заводить на ИИС деньги “на всякий случай”'],
        [q('С какой даты считается срок ИИС-3?', ['С даты открытия счёта','С даты первой покупки акции','С даты первого вычета'],0,'Минимальный срок считается с открытия счёта.'), q('Что обычно происходит при досрочном закрытии?', ['Льготы теряются, полученные вычеты нужно вернуть','Вычеты удваиваются','Счёт продолжает работать без изменений'],0,'Досрочное закрытие нарушает условия льгот.'), q('Почему ИИС-3 не подходит для резерва?', ['Деньги могут понадобиться быстро, а счёт рассчитан на срок','Потому что его нельзя пополнять','Потому что на нём нельзя покупать облигации'],0,'Резерв должен быть доступен без потери налоговых условий.')] ),
      lesson('iis-4','ИИС-3 или брокерский счёт','8 минут','После урока вы поймете, когда лучше использовать ИИС-3, а когда обычный брокерский счёт.', ['брокерский счёт','ИИС-3','цель'], 'portfolio',
        ['ИИС-3 и обычный брокерский счёт не конкурируют, а дополняют друг друга. Брокерский счёт удобен для гибкости: пополнить, купить, продать и вывести деньги без условий ИИС.', 'ИИС-3 лучше подходит для долгосрочной части капитала. Если у вас есть официальный доход и горизонт от нескольких лет, налоговые льготы могут повысить итоговый результат.'],
        {title:'Практичный подход', text:'Для краткосрочных целей используйте брокерский счёт или консервативные инструменты. Для долгосрочных накоплений можно выделить отдельную часть на ИИС-3.'},
        'Не обязательно выбирать только один счёт. Важно распределить задачи между ними.', ['Отделить краткосрочные и долгосрочные цели','Понять, где нужна гибкость','Рассчитать выгоду от ИИС-3'],
        [q('Для чего удобен обычный брокерский счёт?', ['Для большей гибкости вывода средств','Для гарантированного вычета','Для отмены рыночного риска'],0,'На обычном счёте нет условий минимального срока ИИС.'), q('Когда ИИС-3 может быть особенно полезен?', ['При долгосрочной цели и наличии НДФЛ','Если деньги нужны завтра','Если инвестор не хочет изучать условия'],0,'Льготы ИИС-3 раскрываются на долгом сроке.'), q('Можно ли совмещать счета?', ['Да, под разные задачи','Нет, это запрещено всегда','Только при покупке золота'],0,'Брокерский счёт и ИИС-3 могут дополнять друг друга.')] ),
      lesson('iis-5','План действий с ИИС-3','7 минут','После урока вы сможете составить простой план: открыть, пополнить, выбрать инструменты и контролировать условия.', ['план','пополнение','контроль'], 'iis',
        ['Хороший план по ИИС-3 состоит из нескольких простых шагов: открыть счёт, определить ежегодную сумму пополнений, выбрать инструменты под срок и риск, не забывать про налоговый вычет.', 'Не обязательно пополнять ИИС одной суммой. Можно делать это постепенно: ежемесячно, ежеквартально или ближе к концу года. Главное — помнить, что вычет считается за календарный год пополнения.'],
        {title:'В АКБФ', text:'После открытия счёта следите за портфелем, историей операций и документами. Если возникают вопросы по ИИС-3, лучше уточнить условия до сделки или вывода средств.'},
        'ИИС-3 работает лучше, когда есть дисциплина: регулярные пополнения, понятный портфель и контроль налоговых сроков.', ['Выбрать сумму ежегодного пополнения','Запланировать подачу на вычет','Проверять состав портфеля хотя бы раз в квартал'],
        [q('Когда можно получить вычет за пополнение?', ['В следующем году после пополнения','В тот же день','Только через 10 лет'],0,'Вычет оформляется после окончания года, в котором был взнос.'), q('Что важно контролировать по ИИС-3?', ['Срок, пополнения, налоговые условия и состав портфеля','Только цвет кнопки покупки','Только количество приложений'],0,'ИИС-3 требует дисциплины и понимания правил.'), q('Как можно пополнять ИИС-3?', ['Постепенно или одной суммой в течение года','Только 1 января','Только после покупки акций'],0,'Формат пополнения можно выбрать под свой бюджет.')] )
    ]
  },
  {
    id:'bonds', icon:'🛡️', title:'Облигации', subtitle:'Купоны, НКД, доходность, рейтинг и выбор выпуска.', level:'База', track:'deep', accent:'#2a74b9', visual:'bonds',
    lessons:[
      lesson('bonds-1','Облигация простыми словами','7 минут','После урока вы поймете, почему облигация похожа на заем, но торгуется на бирже.', ['номинал','купон','эмитент'], 'bond', ['Покупая облигацию, инвестор даёт деньги эмитенту: государству, региону или компании. Взамен эмитент обещает платить купоны и вернуть номинал в дату погашения.', 'Облигации часто воспринимают как спокойный инструмент, но риск есть и здесь. Эмитент может столкнуться с финансовыми трудностями, а рыночная цена бумаги может меняться до погашения.'], {title:'Карточка выпуска', text:'В АКБФ удобно смотреть основные параметры выпуска: эмитент, срок, купон, доходность, рейтинг, дату погашения и доступность для неквалифицированного инвестора.'}, 'Облигация понятнее, если смотреть не на одно число, а на набор параметров.', ['Найти номинал','Проверить купон и срок','Посмотреть рейтинг и ликвидность'], [q('Что делает инвестор, покупая облигацию?', ['Даёт деньги эмитенту в долг','Покупает долю в компании','Открывает вклад'],0,'Облигация — долговой инструмент.'), q('Что такое номинал?', ['Сумма, которую эмитент должен вернуть при погашении','Комиссия брокера','Дивиденд'],0,'Номинал возвращается по условиям выпуска.'), q('Есть ли риск в облигациях?', ['Да, есть кредитный и рыночный риск','Нет, доход всегда гарантирован','Только если это ОФЗ'],0,'Даже облигации требуют оценки риска.')] ),
      lesson('bonds-2','Купон, НКД и доходность','9 минут','После урока вы поймете, почему купонная ставка не равна доходности к погашению.', ['купон','НКД','YTM'], 'bond', ['Купон — регулярная выплата по облигации. Но итоговая доходность зависит не только от купона: важны цена покупки, срок до погашения, налоги и накопленный купонный доход.', 'НКД — часть купона, накопленная с последней выплаты. При покупке облигации покупатель платит продавцу НКД, а при следующем купоне получает выплату полностью.'], {title:'Пример', text:'Если облигация с номиналом 1 000 ₽ покупается за 950 ₽, инвестор потенциально зарабатывает не только купоны, но и разницу до номинала при погашении.'}, 'Всегда смотрите доходность к погашению, а не только размер купона.', ['Сравнить купон и YTM','Посчитать НКД','Проверить дату следующего купона'], [q('Почему купон не равен полной доходности?', ['Важны цена, срок и погашение','Потому что купон не существует','Потому что налог всегда 0%'],0,'Доходность складывается из нескольких факторов.'), q('Что такое НКД?', ['Накопленная часть купона между выплатами','Название рейтинга','Комиссия фонда'],0,'НКД компенсирует продавцу накопленную часть купонного дохода.'), q('Что показывает YTM?', ['Ориентир доходности к погашению','Только размер комиссии','Количество акций'],0,'YTM помогает сравнивать облигации между собой.')] ),
      lesson('bonds-3','Надёжность и рейтинг','8 минут','После урока вы поймете, почему высокая доходность требует проверки эмитента.', ['рейтинг','кредитный риск','ликвидность'], 'risk', ['Чем выше доходность облигации, тем внимательнее стоит искать причину. Иногда высокая доходность связана не с подарком рынка, а с повышенным риском эмитента или низкой ликвидностью.', 'Кредитный рейтинг помогает оценить способность эмитента выполнять обязательства. Но рейтинг — это не гарантия, а ориентир, который нужно смотреть вместе с отчётностью и условиями выпуска.'], {title:'Практика выбора', text:'Перед покупкой корпоративной облигации проверьте рейтинг эмитента, срок, объём выпуска и историю выплат. Если параметры непонятны, лучше начать с более прозрачных инструментов.'}, 'Доходность без анализа риска может быть ловушкой.', ['Проверить рейтинг','Понять, чем занимается эмитент','Не покупать выпуск только из-за высокой ставки'], [q('Что помогает оценить кредитный риск?', ['Кредитный рейтинг','Цвет логотипа','Размер кнопки покупки'],0,'Рейтинг — один из ориентиров надежности.'), q('Высокая доходность всегда лучше?', ['Нет, она может означать повышенный риск','Да, риск не важен','Да, если срок короткий'],0,'Высокая доходность требует дополнительной проверки.'), q('Что такое ликвидность?', ['Возможность купить или продать актив близко к рыночной цене','Размер купона','Дата отчёта'],0,'Низкая ликвидность может осложнить продажу.')] ),
      lesson('bonds-4','Оферта, амортизация и ставка ЦБ','8 минут','После урока вы поймете, почему условия выпуска меняют результат инвестора.', ['оферта','амортизация','ключевая ставка'], 'bond', ['Оферта — дата, когда облигацию можно предъявить к выкупу или когда эмитент может изменить условия. Амортизация — частичное погашение номинала по графику.', 'На цены облигаций влияет ключевая ставка. Когда ставки растут, старые облигации с низкими купонами часто дешевеют. Когда ставки снижаются, длинные облигации могут дорожать.'], {title:'Что проверить в карточке', text:'Если у выпуска есть оферта или амортизация, смотрите не только дату погашения, но и ближайшую значимую дату. Она может сильнее влиять на доходность.'}, 'Чем сложнее условия, тем внимательнее нужен расчёт.', ['Найти дату оферты','Проверить амортизацию','Сравнить доходность с текущими ставками'], [q('Что такое амортизация облигации?', ['Частичное погашение номинала по графику','Рост цены акции','Комиссия брокера'],0,'При амортизации номинал возвращается частями.'), q('Как рост ставок часто влияет на старые облигации?', ['Может снижать их рыночную цену','Всегда повышает цену','Не влияет никогда'],0,'Новые выпуски могут стать доходнее, поэтому старые дешевеют.'), q('Почему оферта важна?', ['Она может изменить срок и условия инвестора','Она отменяет налоги','Она превращает облигацию в акцию'],0,'Оферта — ключевая дата для расчета результата.')] ),
      lesson('bonds-5','Как выбрать облигацию','9 минут','После урока вы сможете пройти базовый чек-лист перед покупкой облигации.', ['чек-лист','сравнение','портфель'], 'bond', ['Выбор облигации начинается не с самой высокой доходности, а с цели. Для спокойной части портфеля подойдут более надёжные и ликвидные выпуски. Для повышенной доходности придётся принимать больше риска.', 'Сравнивайте облигации по сроку, доходности, рейтингу, ликвидности, налогам, оферте и амортизации. Если выпуск кажется сложным, это уже сигнал не торопиться.'], {title:'В АКБФ', text:'В подборках первичных размещений и карточках инструментов обращайте внимание на рейтинг, срок, купонный период, ориентир доходности и доступность для неквалифицированных инвесторов.'}, 'Хорошая облигация — та, которая подходит вашей цели и уровню риска.', ['Сравнить 2–3 выпуска','Проверить ключевые даты','Не вкладывать всё в одного эмитента'], [q('С чего начинается выбор облигации?', ['С цели и допустимого риска','С самой большой цифры доходности','С названия эмитента'],0,'Цель определяет срок и уровень риска.'), q('Почему не стоит вкладывать всё в одного эмитента?', ['Чтобы снизить риск одной компании','Чтобы увеличить комиссию','Чтобы отменить налоги'],0,'Диверсификация важна и в облигациях.'), q('Что нужно проверить перед покупкой?', ['Срок, рейтинг, доходность, оферту и ликвидность','Только цвет графика','Только количество купонов'],0,'Проверка снижает риск ошибки.')] )
    ]
  },
  {
    id:'stocks', icon:'📈', title:'Акции', subtitle:'Доля в бизнесе, дивиденды, стратегии, отчётность и риски.', level:'База', track:'deep', accent:'#13aa7a', visual:'stocks',
    lessons:[
      lesson('stocks-1','Акция — доля в бизнесе','7 минут','После урока вы поймете, как инвестор зарабатывает на акциях и почему доход не гарантирован.', ['акция','дивиденды','рост цены'], 'stock', ['Акция — это доля в компании. Покупая акцию, инвестор становится совладельцем бизнеса и рассчитывает заработать на росте цены или дивидендах.', 'Но акция не обещает фиксированный доход. Цена зависит от ожиданий рынка, результатов бизнеса, новостей, ставок и общей ситуации в экономике.'], {title:'В приложении', text:'На карточке акции в АКБФ Трейд полезно смотреть цену, дневную динамику, график, описание компании и доступные действия “Купить” и “Продать”.'}, 'Перед покупкой акции спросите: за счёт чего бизнес может стать дороже?', ['Понять бизнес компании','Посмотреть динамику цены','Не покупать только из-за популярности'], [q('Что такое акция?', ['Доля в бизнесе','Долг компании','Банковский вклад'],0,'Акция даёт участие в бизнесе.'), q('Какие два источника дохода возможны по акциям?', ['Рост цены и дивиденды','Купон и номинал','Только налоговый вычет'],0,'Акции могут приносить доход через рост цены и выплаты.'), q('Гарантированы ли дивиденды?', ['Нет, решение зависит от компании и акционеров','Да, всегда','Только у всех банков'],0,'Дивиденды могут изменяться или отменяться.')] ),
      lesson('stocks-2','Почему меняется цена акции','8 минут','После урока вы поймете, какие факторы двигают котировки.', ['прибыль','ожидания','новости'], 'stock', ['В долгосрочной перспективе цена акции зависит от бизнеса: выручки, прибыли, долга, перспектив отрасли и качества управления. Но в краткосрочном периоде цена может резко реагировать на новости и ожидания.', 'Иногда компания публикует хороший отчёт, но акция падает: рынок ждал ещё лучших результатов. Поэтому важны не только факты, но и ожидания инвесторов.'], {title:'Пример', text:'Если компания увеличила прибыль, но одновременно вырос долг и ухудшился прогноз, рынок может отреагировать сдержанно. Смотрите на картину целиком.'}, 'Цена акции — это не только сегодняшняя прибыль, но и ожидания будущего.', ['Понять, почему цена изменилась','Не реагировать на одну новость без анализа','Смотреть отчётность и прогнозы'], [q('Что влияет на цену акции?', ['Финансовые результаты, ожидания и новости','Только номинал','Только дата покупки'],0,'Цена формируется ожиданиями рынка и состоянием бизнеса.'), q('Почему акция может упасть после неплохого отчёта?', ['Рынок ожидал результата лучше','Потому что отчёты не важны','Потому что дивиденды запрещены'],0,'Ожидания инвесторов часто уже заложены в цену.'), q('Что важно для долгосрочного инвестора?', ['Качество бизнеса и финансовые показатели','Только дневной график','Количество комментариев в сети'],0,'Долгосрочный результат связан с бизнесом компании.')] ),
      lesson('stocks-3','Дивиденды и календарь выплат','8 минут','После урока вы поймете, как работает дивидендная доходность и почему после отсечки цена может падать.', ['дивиденды','отсечка','доходность'], 'dividend', ['Дивиденды — часть прибыли, которую компания распределяет между акционерами. Чтобы получить выплату, нужно владеть акцией на дату закрытия реестра.', 'После дивидендной отсечки цена акции часто снижается примерно на размер дивиденда. Это называют дивидендным гэпом. Поэтому покупка “ради дивиденда” прямо перед отсечкой не всегда даёт лёгкую прибыль.'], {title:'Календарь АКБФ', text:'Дивидендные даты удобно проверять в календаре дивидендов на сайте АКБФ: дата закрытия реестра, размер выплаты и последний день покупки помогают планировать действия заранее.'}, 'Дивидендная доходность считается от цены акции, но не отменяет рыночный риск.', ['Найти дату отсечки','Посчитать доходность после налога','Учесть возможный дивидендный гэп'], [q('Что такое дивиденды?', ['Часть прибыли компании для акционеров','Процент по облигации','Комиссия биржи'],0,'Дивиденды выплачиваются по решению компании.'), q('Что такое дивидендный гэп?', ['Снижение цены после отсечки примерно на размер дивиденда','Рост купона','Смена брокера'],0,'После отсечки новые покупатели уже не получают ближайший дивиденд.'), q('Где удобно смотреть даты выплат?', ['В календаре дивидендов на сайте АКБФ','В настройках телефона','В договоре аренды'],0,'Календарь помогает не пропустить ключевые даты.')] ),
      lesson('stocks-4','Стратегии: рост, стоимость, дивиденды','9 минут','После урока вы поймете, почему разные акции покупают по разным причинам.', ['рост','стоимость','дивиденды'], 'portfolio', ['Акции роста покупают из-за ожиданий быстрого развития бизнеса. Они могут давать сильный результат, но часто чувствительны к разочарованиям и ставкам.', 'Акции стоимости — это более зрелые компании со стабильным бизнесом. Дивидендная стратегия делает акцент на регулярных выплатах, но дивиденды тоже не гарантированы.'], {title:'Как выбирать', text:'Определите, какую роль акция играет в портфеле: рост капитала, дивидендный поток или баланс. Тогда проще понять, какой риск вы принимаете.'}, 'Одна стратегия не лучше другой. Важнее, подходит ли она вашей цели и сроку.', ['Определить роль акции в портфеле','Не смешивать спекуляцию и долгосрочную цель','Сравнивать риски стратегий'], [q('Что характерно для акций роста?', ['Ожидание быстрого развития бизнеса','Гарантированный купон','Отсутствие риска'],0,'Акции роста зависят от будущих ожиданий.'), q('Что важно для дивидендной стратегии?', ['Стабильность выплат и дивидендная политика','Только красивая цена','Наличие фьючерсов'],0,'Дивиденды зависят от прибыли и решений акционеров.'), q('Почему стратегия должна соответствовать цели?', ['Иначе инвестор может не выдержать риск или срок','Потому что все акции одинаковые','Потому что брокер запретит сделки'],0,'Комфортный риск помогает сохранять дисциплину.')] ),
      lesson('stocks-5','Отчётность, мультипликаторы и риски','10 минут','После урока вы поймете, какие показатели помогают оценить компанию.', ['выручка','прибыль','P/E','долг'], 'stock', ['Фундаментальный анализ помогает понять, как работает бизнес. Смотрите выручку, прибыль, долг, денежный поток и дивидендную политику. Важна не только цифра, но и динамика.', 'Мультипликаторы помогают сравнивать компании между собой. Например, P/E показывает, во сколько годовых прибылей рынок оценивает бизнес. Но один показатель нельзя использовать отдельно от остальных.'], {title:'Простой разбор', text:'Если компания растит выручку, сохраняет прибыль, контролирует долг и платит понятные дивиденды, её проще анализировать. Но даже сильный бизнес может стоить слишком дорого.'}, 'Не покупайте акцию только по одному мультипликатору. Смотрите бизнес, отрасль и риски.', ['Посмотреть выручку и прибыль','Оценить долг','Сравнить P/E с отраслью'], [q('Что показывает P/E?', ['Во сколько годовых прибылей рынок оценивает компанию','Размер купона','Срок ИИС'],0,'P/E помогает оценить стоимость компании относительно прибыли.'), q('Почему важна динамика показателей?', ['Она показывает, улучшается или ухудшается бизнес','Она отменяет риск','Она гарантирует дивиденды'],0,'Одна цифра без динамики мало что говорит.'), q('Можно ли принимать решение по одному мультипликатору?', ['Нет, нужен комплексный анализ','Да, всегда','Только если P/E высокий'],0,'Один показатель может искажать картину.')] )
    ]
  },
  {
    id:'funds', icon:'🧩', title:'Фонды', subtitle:'БПИФы, ETF, комиссии, диверсификация и выбор фонда.', level:'База', track:'deep', accent:'#7b61ff', visual:'funds',
    lessons:[
      lesson('funds-1','Фонд как готовая корзина','7 минут','После урока вы поймете, как один пай даёт доступ к набору активов.', ['БПИФ','пай','диверсификация'], 'fund', ['Фонд собирает внутри разные активы: акции, облигации, золото или инструменты денежного рынка. Покупая пай, инвестор получает долю в этой корзине.', 'Это удобно, когда сложно выбрать отдельные бумаги. Фонд помогает распределить риск и начать с небольшой суммы, но не гарантирует доходность.'], {title:'В АКБФ', text:'Пай фонда покупается как обычная ценная бумага: через карточку инструмента и кнопку покупки. Перед сделкой смотрите стратегию фонда, состав и комиссию.'}, 'Фонд снижает риск одной бумаги, но не отменяет риск рынка.', ['Понять состав фонда','Проверить комиссию','Оценить, какую роль фонд играет в портфеле'], [q('Что покупает инвестор в фонде?', ['Пай — долю в портфеле фонда','Один банковский вклад','Гарантию дохода'],0,'Пай даёт участие в активах фонда.'), q('Главный плюс фонда для новичка?', ['Диверсификация одной покупкой','Отсутствие риска','Обязательный доход'],0,'Фонд помогает распределить капитал между активами.'), q('Гарантирует ли фонд доход?', ['Нет','Да','Только если фонд зелёный'],0,'Цена пая может снижаться.')] ),
      lesson('funds-2','Как устроен фонд и комиссии','8 минут','После урока вы поймете, кто управляет фондом и как комиссия влияет на результат.', ['УК','комиссия','состав'], 'fund', ['Фондом управляет управляющая компания. Она выбирает активы по стратегии фонда, следит за составом и публикует информацию для инвесторов.', 'Комиссия фонда обычно уже учтена в стоимости пая. Отдельно каждый день её не видно, но она снижает итоговый результат. Поэтому два похожих фонда стоит сравнивать по комиссии и качеству управления.'], {title:'Пример', text:'Если два фонда следуют похожей стратегии, фонд с меньшей комиссией при прочих равных оставит инвестору больше результата.'}, 'Комиссия кажется маленькой, но на длинном сроке имеет значение.', ['Найти комиссию фонда','Проверить управляющую компанию','Сравнить похожие фонды'], [q('Кто управляет фондом?', ['Управляющая компания','Каждый инвестор отдельно','Биржевой стакан'],0,'УК управляет активами по стратегии фонда.'), q('Где учитывается комиссия фонда?', ['В стоимости активов и пая','Только при открытии счёта','В дивидендах'],0,'Комиссия обычно удерживается внутри фонда.'), q('Что сравнить у похожих фондов?', ['Комиссию, состав и качество следования стратегии','Только название','Только цвет иконки'],0,'Сравнение помогает выбрать более подходящий фонд.')] ),
      lesson('funds-3','Какие бывают фонды','8 минут','После урока вы поймете разницу между биржевыми и небиржевыми фондами.', ['БПИФ','ОПИФ','ЗПИФ'], 'fund', ['Биржевые фонды торгуются на бирже, поэтому их можно купить и продать в торговый день через брокера. Это делает их удобными для частного инвестора.', 'ОПИФы, интервальные и закрытые фонды могут иметь другие правила покупки и погашения. Некоторые фонды подходят только квалифицированным инвесторам или требуют прохождения тестирования.'], {title:'Как выбирать', text:'Начинающему инвестору чаще проще начать с ликвидных биржевых фондов, где понятны цена пая, комиссия и состав.'}, 'Чем сложнее фонд, тем внимательнее нужно читать правила.', ['Понять, торгуется ли фонд на бирже','Проверить ограничения для инвестора','Посмотреть правила погашения'], [q('Чем удобен биржевой фонд?', ['Паи можно купить и продать на бирже','Он всегда гарантирует доход','Он не имеет комиссии'],0,'Биржевые фонды доступны через брокера в торговые дни.'), q('Что важно у закрытых фондов?', ['Правила выхода и срок','Только логотип','Количество лайков'],0,'У ЗПИФов могут быть ограничения на погашение.'), q('Для кого некоторые фонды могут быть недоступны?', ['Для неквалифицированных инвесторов без теста или статуса','Для всех клиентов банка','Только для брокеров'],0,'У сложных фондов бывают ограничения.')] ),
      lesson('funds-4','Как выбрать фонд','8 минут','После урока вы сможете пройти короткий чек-лист перед покупкой фонда.', ['индекс','комиссия','ошибка следования'], 'fund', ['Сначала поймите, какую задачу решает фонд: акции, облигации, денежный рынок, золото или смешанный портфель. Потом смотрите состав, комиссию, ликвидность и размер активов.', 'Для индексных фондов важна ошибка следования: насколько точно фонд повторяет свой ориентир. Чем меньше расхождение, тем аккуратнее фонд следует стратегии.'], {title:'Практика', text:'Если фонд нужен для короткого хранения денег, смотрите фонды денежного рынка. Если для роста капитала — фонд акций. Если для защиты части портфеля — фонды золота или облигаций.'}, 'Фонд должен соответствовать задаче портфеля, а не просто казаться популярным.', ['Записать задачу фонда','Проверить комиссию и состав','Не покупать несколько одинаковых фондов без смысла'], [q('С чего начать выбор фонда?', ['С задачи в портфеле','С самой красивой картинки','С последней буквы тикера'],0,'Задача определяет тип фонда.'), q('Что такое ошибка следования?', ['Расхождение доходности фонда и ориентира','Ошибка в паспорте','Комиссия брокера'],0,'Она показывает, насколько точно фонд следует индексу.'), q('Почему важна комиссия?', ['Она снижает итоговый результат','Она увеличивает доходность гарантированно','Она отменяет риск'],0,'На длинном сроке комиссия заметно влияет на капитал.')] )
    ]
  },
  {
    id:'gold', icon:'🟡', title:'Золото', subtitle:'Физическое золото, ОМС, биржа, фонды и защитная роль.', level:'Прокачать', track:'deep', accent:'#d7a40f', visual:'gold',
    lessons:[
      lesson('gold-1','Зачем инвесторы покупают золото','7 минут','После урока вы поймете, почему золото считают защитным активом и где у него риски.', ['золото','защита','диверсификация'], 'gold', ['Золото исторически воспринимается как актив на периоды неопределенности. Оно не зависит от одного эмитента и может вести себя иначе, чем акции или облигации.', 'Но золото не гарантирует рост. Его цена может долго стоять на месте или снижаться. Поэтому золото обычно используют как часть портфеля, а не как единственный инструмент.'], {title:'Роль в портфеле', text:'Золото может быть небольшой защитной долей портфеля. Размер зависит от вашей цели, срока и готовности к колебаниям цены.'}, 'Золото — не магическая защита, а один из инструментов диверсификации.', ['Понять роль золота в портфеле','Не вкладывать всё в один металл','Оценить срок инвестирования'], [q('Почему золото добавляют в портфель?', ['Для диверсификации и защитной роли','Для гарантированного дохода','Чтобы заменить все активы'],0,'Золото может вести себя иначе, чем другие активы.'), q('Гарантирует ли золото рост?', ['Нет','Да всегда','Только в рублях'],0,'Цена золота тоже колеблется.'), q('Как разумнее использовать золото?', ['Как часть портфеля','Как единственный актив','Как замену резерву'],0,'Доля золота должна соответствовать стратегии.')] ),
      lesson('gold-2','Слитки, монеты и ОМС','8 минут','После урока вы поймете, чем физическое золото отличается от банковского металлического счёта.', ['слиток','монета','ОМС'], 'gold', ['Физическое золото — слитки и монеты. У него есть понятная материальная форма, но есть и минусы: хранение, проверка состояния, спред между покупкой и продажей.', 'ОМС привязан к цене металла, но физического золота на руках нет. Доход возможен при росте курса, но государственное страхование вкладов на такие счета не распространяется.'], {title:'Пример со спредом', text:'Если банк продаёт золото дороже, чем покупает обратно, инвестору нужно дождаться такого роста цены, который перекроет эту разницу.'}, 'Перед покупкой физического золота считайте не только цену грамма, но и условия обратной продажи.', ['Узнать цену покупки и продажи','Понять условия хранения','Проверить налоговые последствия'], [q('Что такое спред?', ['Разница между ценой покупки и продажи','Размер купона','Название фонда'],0,'Спред влияет на итоговый результат.'), q('Застрахован ли ОМС как вклад?', ['Нет','Да до любой суммы','Только в золоте'],0,'ОМС не подпадает под страхование вкладов.'), q('Что важно сохранить при покупке слитка?', ['Документы и сертификат','Скрин обоев','Любую упаковку без документов'],0,'Документы пригодятся при продаже.')] ),
      lesson('gold-3','Золото на бирже и фонды','8 минут','После урока вы поймете, как инвестировать в золото без слитков.', ['биржевое золото','фонд','ликвидность'], 'gold', ['На бирже можно купить инструменты, связанные с ценой золота: биржевое золото, фонды на золото или акции золотодобытчиков. Это часто удобнее, чем хранить слиток дома или в банке.', 'Фонд на золото позволяет купить пай, цена которого зависит от стоимости металла. Но внутри есть комиссия управляющей компании, а цена пая может снижаться.'], {title:'В приложении', text:'Пай фонда или акция золотодобытчика покупается как обычный биржевой инструмент: через карточку инструмента, заявку и подтверждение сделки.'}, 'Биржевые инструменты удобнее по ликвидности, но у каждого есть свои риски.', ['Сравнить фонд и физическое золото','Проверить комиссию фонда','Не путать золото и акции золотодобытчика'], [q('Чем фонд на золото отличается от слитка?', ['Покупается как биржевой инструмент и имеет комиссию','Всегда приносит купон','Не меняется в цене'],0,'Фонд удобнее торговать, но он не гарантирует доход.'), q('Акция золотодобытчика — это золото?', ['Нет, это доля в бизнесе компании','Да, это грамм металла','Да, это ОМС'],0,'На акции влияет не только золото, но и бизнес компании.'), q('Почему биржевой инструмент может быть удобнее слитка?', ['Его проще купить и продать в приложении','Он не имеет риска','Он гарантирует рост'],0,'Ликвидность обычно выше, но риск остаётся.')] ),
      lesson('gold-4','Золотые облигации и фьючерсы','9 минут','После урока вы поймете, почему инструменты на золото могут быть сложными.', ['золотые облигации','фьючерсы','сложные инструменты'], 'risk', ['Некоторые облигации могут быть привязаны к цене золота: номинал и купон меняются вместе с учетной ценой металла. Это добавляет потенциальную защиту, но усложняет расчёт результата.', 'Фьючерсы на золото — инструменты срочного рынка. Они подходят не всем: результат может меняться быстро, а убыток иногда превышает первоначальное обеспечение. Начинающему инвестору стоит подходить к ним особенно осторожно.'], {title:'Правило осторожности', text:'Если инструмент зависит сразу от цены золота, курса валюты, ставки и условий выпуска, не покупайте его без полного понимания механики.'}, 'Сложный инструмент не становится безопасным только потому, что связан с золотом.', ['Понять, от чего зависит результат','Проверить доступность и тестирование','Не использовать фьючерсы без опыта'], [q('Что усложняет золотые облигации?', ['Привязка номинала и купона к цене золота','Фиксированный вклад','Отсутствие эмитента'],0,'Результат зависит от металла, курса и условий выпуска.'), q('Кому подходят фьючерсы?', ['Опытным инвесторам, понимающим срочный рынок','Любому новичку без подготовки','Только владельцам слитков'],0,'Фьючерсы требуют знаний и тестирования.'), q('Что главное перед покупкой сложного инструмента?', ['Понять механику и риски','Смотреть только на обещанную доходность','Нажать купить быстрее'],0,'Сначала понимание, потом сделка.')] )
    ]
  }
];
function lesson(id,title,duration,goal,concepts,practiceType,paragraphs,example,remember,checklist,tests){return{id,title,duration,goal,concepts,practiceType,paragraphs,example,remember,checklist,tests};}
function q(q,answers,correct,expl){return{q,answers,correct,expl};}

const STORAGE_KEY='akbf-academy-ecosystem-v3-progress';
const state={courseId:'start',lessonId:'start-1',route:'catalog',filter:'all',deferredPrompt:null,progress:{}};
const $=id=>document.getElementById(id);
const els={splash:$('splashScreen'),catalog:$('catalogView'),courseGrid:$('courseGrid'),lessonView:$('lessonView'),lessonPanel:$('lessonPanel'),widgetPanel:$('widgetPanel'),practicePanel:$('practicePanel'),testPanel:$('testPanel'),completion:$('completionPanel'),courseSwitcher:$('courseSwitcher'),lessonNav:$('lessonNav'),lessonSheet:$('lessonSheet'),lessonSheetBackdrop:$('lessonSheetBackdrop'),lessonSheetList:$('lessonSheetList'),sheetCourseTitle:$('sheetCourseTitle'),sheetCourseSub:$('sheetCourseSub'),mobileCourseName:$('mobileCourseName'),completedLessons:$('completedLessons'),progressTotal:$('progressTotal'),completedTests:$('completedTests'),testsTotal:$('testsTotal'),progressFill:$('progressFill'),progressPercent:$('progressPercent'),completionHint:$('completionHint'),openCompletion:$('openCompletion'),downloadCertificate:$('downloadCertificate'),certificateNameInput:$('certificateNameInput'),certificateName:$('certificateName'),certificateCourse:$('certificateCourse'),certificateDate:$('certificateDate'),certificateStatus:$('certificateStatus')};
function load(){try{state.progress=JSON.parse(localStorage.getItem(STORAGE_KEY)||'{}')}catch{state.progress={}}}
function save(){localStorage.setItem(STORAGE_KEY,JSON.stringify(state.progress))}
function course(){return COURSES.find(c=>c.id===state.courseId)||COURSES[0]}
function lessonObj(){const c=course();return c.lessons.find(l=>l.id===state.lessonId)||c.lessons[0]}
function courseProgress(c=course()){const done=c.lessons.filter(l=>isLessonDone(c.id,l.id)).length;const score=c.lessons.reduce((s,l)=>s+lessonScore(c.id,l.id),0);return{done,total:c.lessons.length,score,max:c.lessons.length*3,percent:c.lessons.length?Math.round(done/c.lessons.length*100):0}}
function key(cId,lId){return `${cId}:${lId}`}
function getAnswers(cId,lId){return state.progress.answers?.[key(cId,lId)]||{}}
function isLessonDone(cId,lId){const c=COURSES.find(x=>x.id===cId),l=c?.lessons.find(x=>x.id===lId);return l && Object.keys(getAnswers(cId,lId)).length===l.tests.length}
function lessonScore(cId,lId){const c=COURSES.find(x=>x.id===cId),l=c?.lessons.find(x=>x.id===lId),ans=getAnswers(cId,lId);if(!l)return 0;return Object.entries(ans).reduce((s,[i,a])=>s+(l.tests[i]?.correct===a?1:0),0)}
function setCourse(courseId,showLesson=true){state.courseId=courseId;state.lessonId=course().lessons[0].id;state.route=showLesson?'lesson':'catalog';render();scrollMainTop();}
function setLesson(lessonId){state.lessonId=lessonId;state.route='lesson';closeLessonSheet();render();scrollMainTop();}
function scrollMainTop(){setTimeout(()=>{$('main')?.scrollIntoView({behavior:'smooth',block:'start'}); window.scrollTo({top:0,behavior:'smooth'});},0)}
function escapeHtml(s){return String(s||'').replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]))}
function fmt(n){return new Intl.NumberFormat('ru-RU').format(Math.round(n))+' ₽'}
function pct(n){return new Intl.NumberFormat('ru-RU',{maximumFractionDigits:1}).format(n)+'%'}
function render(){renderCourseSwitcher();renderLessonNav();renderProgress();updateTop();document.querySelectorAll('.bottom-link').forEach(b=>b.classList.toggle('active', b.dataset.mobileAction === (state.route==='catalog'?'courses':state.route==='final'?'final':'courses')));els.catalog.classList.toggle('hidden',state.route!=='catalog');els.lessonView.classList.toggle('hidden',state.route!=='lesson');els.completion.classList.toggle('hidden',state.route!=='final');if(state.route==='catalog')renderCatalog();if(state.route==='lesson'){renderLesson();renderWidget();renderPractice();renderTest();}if(state.route==='final')renderCompletion();}
function updateTop(){const c=course();els.mobileCourseName.textContent=state.route==='catalog'?'Выберите курс':c.title;}
function renderCatalog(){const list=COURSES.filter(c=>state.filter==='all'||c.track===state.filter);els.courseGrid.innerHTML=list.map(c=>`<button class="course-card" style="--accent:${c.accent}" data-course="${c.id}"><div class="course-visual"><span class="course-badge">${c.lessons.length} уроков</span>${visualSvg(c.visual)}</div><h3>${c.title}</h3><p>${c.subtitle}</p></button>`).join('');els.courseGrid.querySelectorAll('[data-course]').forEach(btn=>btn.onclick=()=>setCourse(btn.dataset.course,true));document.querySelectorAll('.filter').forEach(btn=>{btn.classList.toggle('active',btn.dataset.filter===state.filter);btn.onclick=()=>{state.filter=btn.dataset.filter;renderCatalog();document.querySelectorAll('.filter').forEach(b=>b.classList.toggle('active',b.dataset.filter===state.filter));}})}
function renderCourseSwitcher(){els.courseSwitcher.innerHTML='<div class="nav-title">Курсы</div>'+COURSES.map(c=>`<button class="course-pill ${c.id===state.courseId?'active':''}" data-course="${c.id}"><span>${c.icon}</span><div>${c.title}<small>${c.lessons.length} уроков</small></div></button>`).join('');els.courseSwitcher.querySelectorAll('[data-course]').forEach(b=>b.onclick=()=>setCourse(b.dataset.course,true));}
function renderLessonNav(){const c=course();const html=c.lessons.map((l,i)=>`<button class="lesson-link ${l.id===state.lessonId?'active':''}" data-lesson="${l.id}"><span class="num">${isLessonDone(c.id,l.id)?'✓':i+1}</span><span><b>${l.title}</b><small>${l.duration}</small></span></button>`).join('');els.lessonNav.innerHTML=html;els.lessonNav.querySelectorAll('[data-lesson]').forEach(b=>b.onclick=()=>setLesson(b.dataset.lesson));els.sheetCourseTitle.textContent=c.title;els.sheetCourseSub.textContent=`${c.lessons.length} уроков`;els.lessonSheetList.innerHTML=html;els.lessonSheetList.querySelectorAll('[data-lesson]').forEach(b=>b.onclick=()=>setLesson(b.dataset.lesson));}
function renderProgress(){const c=course(),p=courseProgress(c);els.completedLessons.textContent=p.done;els.progressTotal.textContent=`из ${p.total} уроков`;els.completedTests.textContent=p.done;els.testsTotal.textContent=p.total;els.progressFill.style.width=p.percent+'%';els.progressPercent.textContent=p.percent+'%';els.completionHint.textContent=p.done===p.total?'Курс завершен. Можно скачать сертификат.':'Пройдите тесты курса, чтобы открыть сертификат.';els.openCompletion.disabled=false;}
function renderLesson(){const c=course(),l=lessonObj(),idx=c.lessons.findIndex(x=>x.id===l.id);els.lessonPanel.innerHTML=`<div class="lesson-hero"><div><span class="chip">${c.icon} ${c.title}</span><h2>${l.title}</h2><p>${l.goal}</p><div class="concepts">${l.concepts.map(x=>`<span>${x}</span>`).join('')}</div></div><div class="lesson-visual">${visualSvg(c.visual)}</div></div><div class="lesson-body">${l.paragraphs.map((p,i)=>`<div class="content-block"><h4>${i===0?'Разберёмся по-человечески':'Что важно понять'}</h4><p>${p}</p></div>`).join('')}<div class="content-block akbf-screen"><div class="mock-phone"><div class="mock-bar"></div><div class="mock-row"></div><div class="mock-row"></div><div class="mock-row"></div><div class="mock-cta"></div></div><div><h4>${l.example.title}</h4><p>${l.example.text}</p></div></div><div class="content-block remember"><h4>Главное за 30 секунд</h4><p>${l.remember}</p></div></div>`;}
function renderWidget(){const l=lessonObj();els.widgetPanel.innerHTML=`<div class="section-head"><div><h3>Практический блок</h3><p class="panel-intro">Двигайте ползунки и смотрите, как меняется результат.</p></div></div><div id="widgetInner"></div>`;const inner=$('widgetInner');
 if(l.practiceType==='inflation') inner.innerHTML=rangeWidget('infl', [['sum','Сумма сегодня',10000,1000000,10000,300000,'₽'],['rate','Инфляция в год',1,20,0.5,7,'%'],['years','Срок',1,15,1,5,'лет']], calcInflation);
 else if(l.practiceType==='goal') inner.innerHTML=rangeWidget('goal', [['target','Цель',50000,3000000,50000,800000,'₽'],['start','Уже есть',0,1000000,10000,100000,'₽'],['month','Пополнение в месяц',1000,100000,1000,20000,'₽'],['yield','Доходность в год',0,25,0.5,10,'%']], calcGoal);
 else if(l.practiceType==='iis') inner.innerHTML=rangeWidget('iis', [['amount','Пополнение за год',10000,1000000,10000,400000,'₽'],['tax','Ставка НДФЛ',13,22,1,13,'%'],['years','Срок ИИС-3',5,10,1,5,'лет'],['yield','Ожидаемая доходность',0,25,0.5,10,'%']], calcIis);
 else if(l.practiceType==='bond') inner.innerHTML=rangeWidget('bond', [['price','Цена покупки',70,120,1,95,'%'],['coupon','Купон',1,25,0.5,14,'%'],['years','Лет до погашения',1,10,1,3,'лет'],['face','Номинал',500,2000,100,1000,'₽']], calcBond);
 else if(l.practiceType==='stock'||l.practiceType==='dividend') inner.innerHTML=rangeWidget('stock', [['price','Цена акции',50,5000,10,1000,'₽'],['shares','Количество',1,100,1,10,'шт'],['div','Дивиденд на акцию',0,500,5,80,'₽'],['growth','Изменение цены',-50,80,1,12,'%']], calcStock);
 else if(l.practiceType==='fund'||l.practiceType==='portfolio') inner.innerHTML=rangeWidget('fund', [['stocks','Акции',0,100,5,45,'%'],['bonds','Облигации',0,100,5,40,'%'],['money','Денежный рынок',0,100,5,10,'%'],['gold','Золото',0,100,5,5,'%']], calcFund);
 else if(l.practiceType==='gold') inner.innerHTML=rangeWidget('gold', [['grams','Граммы золота',1,100,1,10,'г'],['buy','Цена покупки за грамм',3000,15000,100,8000,'₽'],['spread','Спред банка/инструмента',0,20,0.5,5,'%'],['change','Изменение цены',-30,50,1,10,'%']], calcGold);
 else if(l.practiceType==='risk') inner.innerHTML=rangeWidget('risk', [['horizon','Горизонт',1,10,1,5,'лет'],['drop','Комфортная просадка',0,50,5,15,'%'],['stable','Доля спокойных активов',0,100,5,60,'%']], calcRisk);
 bindRanges(); }
function rangeWidget(prefix, fields, calcName){return `<div class="widget-grid">${fields.map(f=>`<label class="field range-field"><span class="range-line">${f[1]} <b id="${prefix}-${f[0]}-value"></b></span><input type="range" id="${prefix}-${f[0]}" min="${f[2]}" max="${f[3]}" step="${f[4]}" value="${f[5]}" data-suffix="${f[6]}"></label>`).join('')}</div><div class="result-box" id="widgetResult"></div><script type="application/json" id="widgetCalc">${calcName.name}</script>`}
function bindRanges(){document.querySelectorAll('#widgetInner input[type=range]').forEach(inp=>inp.addEventListener('input',updateWidget));updateWidget();}
function rangeVal(id){return +$(id).value||0}
function updateRangeLabels(){document.querySelectorAll('#widgetInner input[type=range]').forEach(inp=>{const el=$(inp.id+'-value');if(el)el.textContent=(inp.dataset.suffix==='₽'?fmt(inp.value).replace(' ₽',' ₽'):inp.value+' '+inp.dataset.suffix);});}
function updateWidget(){updateRangeLabels();const type=lessonObj().practiceType;let html='';if(type==='inflation')html=calcInflation();else if(type==='goal')html=calcGoal();else if(type==='iis')html=calcIis();else if(type==='bond')html=calcBond();else if(type==='stock'||type==='dividend')html=calcStock();else if(type==='fund'||type==='portfolio')html=calcFund();else if(type==='gold')html=calcGold();else if(type==='risk')html=calcRisk();$('widgetResult').innerHTML=html;}
function calcInflation(){const sum=rangeVal('infl-sum'), rate=rangeVal('infl-rate')/100, years=rangeVal('infl-years');const future=sum/Math.pow(1+rate,years);return `<strong>${fmt(future)}</strong>Покупательная способность ${fmt(sum)} через ${years} лет при такой инфляции.`}
function calcGoal(){const target=rangeVal('goal-target'),start=rangeVal('goal-start'),month=rangeVal('goal-month'),y=rangeVal('goal-yield')/100/12;let months=0,total=start;while(total<target&&months<600){total=(total+month)*(1+y);months++}return `<strong>${months>=600?'Цель требует пересмотра':Math.ceil(months/12)+' лет'}</strong>Ориентировочный срок достижения цели. Итоговая сумма: ${fmt(total)}.`}
function calcIis(){const amount=rangeVal('iis-amount'),tax=rangeVal('iis-tax')/100,years=rangeVal('iis-years'),yieldY=rangeVal('iis-yield')/100;const deduction=Math.min(amount,400000)*tax;let total=0;for(let i=0;i<years;i++){total=(total+amount+deduction)* (1+yieldY)}return `<strong>Вычет до ${fmt(deduction)} в год</strong>При ежегодном пополнении и реинвестировании вычета ориентировочный капитал через ${years} лет: ${fmt(total)}.`}
function calcBond(){const face=rangeVal('bond-face'),pricePct=rangeVal('bond-price'),couponPct=rangeVal('bond-coupon'),years=rangeVal('bond-years');const price=face*pricePct/100,coupon=face*couponPct/100,ytm=((coupon+(face-price)/years)/((face+price)/2))*100;return `<strong>YTM ≈ ${pct(ytm)}</strong>Цена покупки: ${fmt(price)}. Годовой купон: ${fmt(coupon)}. Купон и доходность могут отличаться.`}
function calcStock(){const price=rangeVal('stock-price'),shares=rangeVal('stock-shares'),div=rangeVal('stock-div'),growth=rangeVal('stock-growth')/100;const cost=price*shares,after=price*(1+growth)*shares,divs=div*shares*0.87;return `<strong>${fmt(after+divs-cost)}</strong>Потенциальный результат с учетом изменения цены и дивидендов после НДФЛ. Дивидендная доходность до налога: ${pct(div/price*100)}.`}
function calcFund(){const s=rangeVal('fund-stocks'),b=rangeVal('fund-bonds'),m=rangeVal('fund-money'),g=rangeVal('fund-gold'),total=s+b+m+g;return `<strong>${total===100?'Портфель собран на 100%':'Сумма долей: '+total+'%'}</strong>Акции отвечают за рост, облигации и денежный рынок — за устойчивость, золото — за дополнительную диверсификацию.`}
function calcGold(){const grams=rangeVal('gold-grams'),buy=rangeVal('gold-buy'),spread=rangeVal('gold-spread')/100,change=rangeVal('gold-change')/100;const cost=grams*buy,sell=grams*buy*(1+change)*(1-spread);return `<strong>${fmt(sell-cost)}</strong>Ориентировочный результат после изменения цены и спреда. Чем выше спред, тем больше должен вырасти металл, чтобы выйти в плюс.`}
function calcRisk(){const h=rangeVal('risk-horizon'),d=rangeVal('risk-drop'),stable=rangeVal('risk-stable');let profile='Консервативный';if(h>=5&&d>=20&&stable<60)profile='Умеренный';if(h>=7&&d>=35&&stable<40)profile='Агрессивный';return `<strong>${profile} профиль</strong>Ориентир зависит от срока, готовности к просадке и доли спокойных активов.`}
function renderPractice(){const c=course(),l=lessonObj();els.practicePanel.innerHTML=`<h3>Мини-чек-лист</h3><p class="panel-intro">Отметьте действия, которые помогут применить урок на практике.</p><div class="practice-list">${l.checklist.map((x,i)=>`<label class="check-row"><input type="checkbox" data-check="${i}" ${state.progress.checks?.[key(c.id,l.id)]?.[i]?'checked':''}> <span>${x}</span></label>`).join('')}</div>`;els.practicePanel.querySelectorAll('input[data-check]').forEach(inp=>inp.onchange=()=>{state.progress.checks=state.progress.checks||{};state.progress.checks[key(c.id,l.id)]={...(state.progress.checks[key(c.id,l.id)]||{}),[inp.dataset.check]:inp.checked};save();});}
function renderTest(){const c=course(),l=lessonObj(),ans=getAnswers(c.id,l.id);els.testPanel.innerHTML=`<div class="section-head"><div><h3>Проверьте себя</h3><p class="panel-intro">После ответа сразу покажем правильный вариант и короткое объяснение.</p></div><span class="chip">${lessonScore(c.id,l.id)} из ${l.tests.length}</span></div><div class="test-list">${l.tests.map((t,qi)=>`<div class="test-card"><div class="test-q">${qi+1}. ${t.q}</div>${t.answers.map((a,ai)=>answerHtml(t,qi,ai,ans[qi])).join('')}<div class="answer-expl ${ans[qi]===undefined?'hidden':''}">${t.expl}</div></div>`).join('')}</div>${navActions()}`;els.testPanel.querySelectorAll('.answer-btn').forEach(btn=>btn.onclick=()=>{const qi=+btn.dataset.q,ai=+btn.dataset.a;state.progress.answers=state.progress.answers||{};state.progress.answers[key(c.id,l.id)]={...getAnswers(c.id,l.id),[qi]:ai};save();renderTest();renderProgress();renderLessonNav();});bindNavActions();}
function answerHtml(t,qi,ai,chosen){let cls='answer-btn';if(chosen!==undefined){if(ai===t.correct)cls+=' correct';else if(ai===chosen)cls+=' wrong'}return `<button class="${cls}" data-q="${qi}" data-a="${ai}" ${chosen!==undefined?'disabled':''}>${t.answers[ai]}</button>`}
function navActions(){const c=course(),idx=c.lessons.findIndex(l=>l.id===state.lessonId);return `<div class="lesson-actions"><button class="btn btn-secondary" data-prev ${idx===0?'disabled':''}>← Предыдущий урок</button><button class="btn btn-primary" data-next>${idx===c.lessons.length-1?'К итогу':'Следующий урок →'}</button></div>`}
function bindNavActions(){const c=course(),idx=c.lessons.findIndex(l=>l.id===state.lessonId);document.querySelector('[data-prev]')?.addEventListener('click',()=>{if(idx>0)setLesson(c.lessons[idx-1].id)});document.querySelector('[data-next]')?.addEventListener('click',()=>{if(idx<c.lessons.length-1)setLesson(c.lessons[idx+1].id);else{state.route='final';render();scrollMainTop();}})}
function renderCompletion(){const c=course(),p=courseProgress(c),complete=p.done===p.total;els.completion.classList.remove('hidden');$('completionTitle').textContent=complete?'Персональный сертификат':'Итог курса';$('completionText').textContent=complete?'Введите ФИО для сертификата. После этого кнопка скачивания станет активной.':'Пройдите все тесты курса, чтобы открыть персональный сертификат.';$('certificateNameField').classList.toggle('hidden',!complete);els.downloadCertificate.disabled=!complete||!els.certificateNameInput.value.trim();$('finalLessons').textContent=`${p.done}/${p.total}`;$('finalTests').textContent=`${p.done}/${p.total}`;$('finalScore').textContent=`${p.score} из ${p.max}`;els.certificateCourse.textContent=c.title;els.certificateDate.textContent=new Date().toLocaleDateString('ru-RU');els.certificateStatus.textContent=complete?'Курс завершен':'В процессе';els.certificateName.textContent=els.certificateNameInput.value.trim()||'ФИО участника';}
function downloadCertificate(){const name=els.certificateNameInput.value.trim();if(!name)return;els.certificateName.textContent=name;els.certificateCourse.textContent=course().title;els.certificateDate.textContent=new Date().toLocaleDateString('ru-RU');const card=$('certificateCard');const fallback=()=>manualCertificate(name,course().title);(async()=>{try{if(document.fonts&&document.fonts.ready)await document.fonts.ready;if(window.html2canvas){const canvas=await html2canvas(card,{scale:3,backgroundColor:null,useCORS:true});return saveCanvas(canvas,'akbf-certificate.png')}fallback()}catch(e){fallback()}})();}
function manualCertificate(name,courseTitle){const canvas=document.createElement('canvas');canvas.width=1240;canvas.height=1754;const ctx=canvas.getContext('2d');ctx.fillStyle='#fffdf7';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.fillStyle='#e9f7f1';ctx.beginPath();ctx.arc(1040,120,260,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#0a7a63';ctx.lineWidth=8;ctx.strokeRect(70,70,1100,1614);ctx.fillStyle='#0a7a63';ctx.font='bold 34px Arial';ctx.fillText('АКБФ Академия Инвестиций',120,170);ctx.fillStyle='#20251f';ctx.font='bold 92px Arial';ctx.fillText('Сертификат',120,350);ctx.font='36px Arial';ctx.fillText('о прохождении курса',120,420);ctx.font='bold 42px Arial';wrapText(ctx,'«'+courseTitle+'»',120,500,980,56);ctx.strokeStyle='rgba(10,122,99,.35)';ctx.beginPath();ctx.moveTo(120,760);ctx.lineTo(1120,760);ctx.stroke();ctx.fillStyle='#20251f';ctx.font='bold 52px Arial';wrapText(ctx,name,120,850,980,64);ctx.beginPath();ctx.moveTo(120,980);ctx.lineTo(1120,980);ctx.stroke();ctx.fillStyle='#526158';ctx.font='30px Arial';wrapText(ctx,'Участник изучил основные понятия курса, выполнил практические задания и прошёл проверочные тесты.',120,1120,980,42);ctx.fillStyle='#20251f';ctx.font='bold 28px Arial';ctx.fillText('Дата',120,1500);ctx.fillText('Статус',700,1500);ctx.font='34px Arial';ctx.fillText(new Date().toLocaleDateString('ru-RU'),120,1555);ctx.fillText('Курс завершен',700,1555);saveCanvas(canvas,'akbf-certificate.png')}
function wrapText(ctx,text,x,y,maxWidth,lineHeight){const words=text.split(' ');let line='';for(const word of words){const test=line+word+' ';if(ctx.measureText(test).width>maxWidth&&line){ctx.fillText(line,x,y);line=word+' ';y+=lineHeight}else line=test}ctx.fillText(line,x,y)}
function saveCanvas(canvas,name){canvas.toBlob(blob=>{if(!blob){const a=document.createElement('a');a.href=canvas.toDataURL('image/png');a.download=name;a.click();return}const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name;document.body.appendChild(a);a.click();a.remove();setTimeout(()=>URL.revokeObjectURL(url),1000)},'image/png')}
function openLessonSheet(){const c=course();els.sheetCourseTitle.textContent=c.title;els.sheetCourseSub.textContent=`${c.lessons.length} уроков`;els.lessonSheet.classList.remove('hidden');els.lessonSheetBackdrop.classList.remove('hidden')}
function closeLessonSheet(){els.lessonSheet.classList.add('hidden');els.lessonSheetBackdrop.classList.add('hidden')}
function scrollToId(id){state.route='lesson';render();setTimeout(()=>$(id)?.scrollIntoView({behavior:'smooth',block:'start'}),20)}
function visualSvg(type){const color='currentColor';const common=`fill="${color}"`;const map={cash:`<svg viewBox="0 0 320 220"><rect x="62" y="76" width="172" height="88" rx="16" ${common} opacity=".16"/><rect x="86" y="56" width="172" height="88" rx="16" ${common} opacity=".22"/><circle cx="172" cy="100" r="28" ${common} opacity=".35"/><circle cx="88" cy="156" r="26" ${common} opacity=".24"/><circle cx="232" cy="58" r="22" ${common} opacity=".24"/></svg>`,iis:`<svg viewBox="0 0 320 220"><rect x="62" y="44" width="196" height="132" rx="22" ${common} opacity=".15"/><path d="M98 90h124M98 120h80M98 150h104" stroke="currentColor" stroke-width="12" stroke-linecap="round" opacity=".65"/><circle cx="228" cy="86" r="26" ${common} opacity=".28"/><text x="210" y="96" font-size="28" font-weight="900" fill="currentColor">%</text></svg>`,bonds:`<svg viewBox="0 0 320 220"><rect x="66" y="62" width="188" height="112" rx="18" ${common} opacity=".16"/><path d="M96 96h128M96 126h96M96 154h118" stroke="currentColor" stroke-width="10" stroke-linecap="round" opacity=".7"/><path d="M226 52l20 20 28-34" stroke="currentColor" stroke-width="12" stroke-linecap="round" fill="none"/></svg>`,stocks:`<svg viewBox="0 0 320 220"><rect x="58" y="58" width="204" height="124" rx="20" ${common} opacity=".14"/><path d="M88 156l44-48 38 28 64-70" stroke="currentColor" stroke-width="14" stroke-linecap="round" stroke-linejoin="round" fill="none"/><path d="M214 66h20v22" stroke="currentColor" stroke-width="14" stroke-linecap="round" fill="none"/></svg>`,funds:`<svg viewBox="0 0 320 220"><circle cx="160" cy="110" r="74" ${common} opacity=".16"/><path d="M160 36a74 74 0 0 1 64 111L160 110z" ${common} opacity=".46"/><path d="M160 110l-54 51a74 74 0 0 1 54-125z" ${common} opacity=".28"/><circle cx="160" cy="110" r="36" fill="#fff" opacity=".75"/></svg>`,gold:`<svg viewBox="0 0 320 220"><rect x="90" y="104" width="86" height="54" rx="10" ${common} opacity=".38"/><rect x="146" y="78" width="86" height="54" rx="10" ${common} opacity=".24"/><rect x="116" y="52" width="86" height="54" rx="10" ${common} opacity=".3"/><circle cx="228" cy="150" r="26" ${common} opacity=".22"/></svg>`};return map[type]||map.cash;}
function updateOnline(){const el=$('offlineBadge');if(el){el.textContent=navigator.onLine?'Онлайн':'Оффлайн';el.classList.toggle('offline',!navigator.onLine)}}
function showAbout(){ $('aboutBackdrop').classList.remove('hidden');$('aboutModal').classList.remove('hidden')}
function hideAbout(){ $('aboutBackdrop').classList.add('hidden');$('aboutModal').classList.add('hidden')}
function init(){load();const savedCourse=localStorage.getItem('akbf-current-course');if(savedCourse&&COURSES.some(c=>c.id===savedCourse))state.courseId=savedCourse;state.lessonId=course().lessons[0].id;setTimeout(()=>els.splash?.classList.add('hidden'),450);render();updateOnline();window.addEventListener('online',updateOnline);window.addEventListener('offline',updateOnline);document.querySelectorAll('[data-filter]').forEach(btn=>btn.onclick=()=>{state.filter=btn.dataset.filter;renderCatalog();document.querySelectorAll('.filter').forEach(b=>b.classList.toggle('active',b.dataset.filter===state.filter));});$('resetProgress').onclick=()=>{state.progress={};save();render()};$('openCompletion').onclick=()=>{state.route='final';render();scrollMainTop()};$('backToCourse').onclick=()=>{state.route='lesson';render();scrollMainTop()};$('downloadCertificate').onclick=downloadCertificate;els.certificateNameInput.oninput=()=>{renderCompletion()};$('showAbout').onclick=showAbout;$('closeAbout').onclick=hideAbout;$('aboutBackdrop').onclick=hideAbout;$('closeLessonSheet').onclick=closeLessonSheet;els.lessonSheetBackdrop.onclick=closeLessonSheet;document.querySelectorAll('.bottom-link').forEach(btn=>btn.onclick=()=>{const a=btn.dataset.mobileAction;if(a==='courses'){state.route='catalog';render();scrollMainTop()}else if(a==='lessons')openLessonSheet();else if(a==='practice')scrollToId('practicePanel');else if(a==='test')scrollToId('testPanel');else if(a==='final'){state.route='final';render();scrollMainTop()}});$('installApp').onclick=async()=>{if(state.deferredPrompt){state.deferredPrompt.prompt();await state.deferredPrompt.userChoice;state.deferredPrompt=null;$('installApp').disabled=true}};window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();state.deferredPrompt=e;$('installApp').disabled=false});if('serviceWorker' in navigator)navigator.serviceWorker.register('./sw.js').catch(()=>{});}
document.addEventListener('DOMContentLoaded',init);
